export function useBusinessClaims() {
  const { user } = useAuth();
  const queryKey = useMemo(() => ['business-claims', user?.id ?? 'guest'], [user?.id]);

  const businessClaimsQuery = useQuery<BusinessClaimListItem[], Error>({
    queryKey,
    enabled: Boolean(user?.id),
