      if (!user?.id) {
        return [];
      }

      const claimsResult = await fetchBusinessClaims(user.id);

      if (claimsResult.error) {
        throw claimsResult.error;
      }

      const bathroomIds = [...new Set(claimsResult.data.map((claim) => claim.bathroom_id))];

      if (!bathroomIds.length) {
